<template>
  <div class="conversor-preco">
    <div class="preco">
      <p>
        Informe o preço
      </p>
      <input :value="precoFormatado" @input="atualizarPreco" inputmode="numeric" placeholder="Preço" />
    </div>
    <div class="peso">
      <p>
        Informe o peso
      </p>
      <input v-model="peso" placeholder="Peso" />
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed, ref } from 'vue';

const precoEmCentavos = ref<number>(0);
const precoFormatado = computed(() => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(precoEmCentavos.value / 100)
});

const peso = ref<string>('');

function atualizarPreco(event: Event) {
  const input = event.target as HTMLInputElement
  const somenteNumeros = input.value.replace(/\D/g, '')
  precoEmCentavos.value = Number(somenteNumeros)
}
</script>

<style scoped>
input {
  padding: 6px;
  font-size: 1rem;
  width: 120px;
}
</style>